const { useState } = React;

function App() {
  const [gpa, setGpa] = useState("");
  const [interests, setInterests] = useState("");

  const submitProfile = () => {
    if (gpa && interests) {
      alert("✅ PROFILE SAVED!\nGPA: " + gpa + "\nInterests: " + interests);
    } else {
      alert("⚠️ Please fill both fields!");
    }
  };

  return React.createElement("div", { style: { padding: "50px", maxWidth: "500px", margin: "auto" } },
    React.createElement("h1", { style: { color: "#007bff", textAlign: "center", fontSize: "36px" } }, "🎓 AI College Counselor"),
    React.createElement("div", { style: { margin: "30px 0" } },
      React.createElement("input", {
        placeholder: "Enter GPA (3.5)",
        value: gpa,
        onChange: (e) => setGpa(e.target.value),
        style: { width: "100%", padding: "15px", fontSize: "18px", borderRadius: "10px", border: "2px solid #ddd", marginBottom: "15px" }
      })
    ),
    React.createElement("div", { style: { marginBottom: "30px" } },
      React.createElement("input", {
        placeholder: "Interests (CS, AI, Mechanical)",
        value: interests,
        onChange: (e) => setInterests(e.target.value),
        style: { width: "100%", padding: "15px", fontSize: "18px", borderRadius: "10px", border: "2px solid #ddd" }
      })
    ),
    React.createElement("button", {
      onClick: submitProfile,
      style: { width: "100%", padding: "18px", background: "#28a745", color: "white", border: "none", borderRadius: "12px", fontSize: "20px", cursor: "pointer" }
    }, "🚀 Start AI Counseling"),
    React.createElement("p", { style: { textAlign: "center", marginTop: "30px", color: "green" } }, "Backend: localhost:5000 ✅")
  );
}

const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(React.createElement(App));
